using namespace std;

// Function to check if the given number is positive, negative, or zero
string checkNumber(int num) {
    if (num > 0) {
        return "Positive";  // Return "Positive" if num is greater than 0
    } else if (num < 0) {
        return "Negative";  // Return "Negative" if num is less than 0
    } else {
        return "Zero";  // Return "Zero" if num is equal to 0
    }
}

int main() {
    int number = -5;

    // Function call to check the number
    string result = checkNumber(number);

    // Display the result
    cout << "The number " << number << " is: " << result << endl;

    return 0;
}
